package main

import (
	"container/heap"
	"math"
)

type Edge struct {
	to   int
	cost int64
}

type State struct {
	node      int
	totalCost int64
	minEdge   int64
}

type PriorityQueue []State

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].totalCost < pq[j].totalCost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	*pq = append(*pq, x.(State))
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

func solve(edges [][]int64, online []bool, k int64) int64 {
	n := len(online)
	graph := make([][]Edge, n)
	for _, e := range edges {
		u, v, cost := e[0], e[1], e[2]
		if u == v {
			continue
		}
		graph[u] = append(graph[u], Edge{int(v), cost})
	}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, State{0, 0, math.MaxInt64})

	maxScore := int64(-1)

	for pq.Len() > 0 {
		current := heap.Pop(&pq).(State)
		u := current.node
		totalCost := current.totalCost
		minEdge := current.minEdge

		if u == n-1 {
			if totalCost <= k {
				if minEdge != math.MaxInt64 {
					if minEdge > maxScore {
						maxScore = minEdge
					}
				}
			}
			continue
		}

		for _, edge := range graph[u] {
			v := edge.to
			if v != n-1 && !online[v] {
				continue
			}
			newTotal := totalCost + edge.cost
			if newTotal > k {
				continue
			}
			newMin := minEdge
			if edge.cost < newMin {
				newMin = edge.cost
			}
			heap.Push(&pq, State{v, newTotal, newMin})
		}
	}

	return maxScore
}
