using namespace std;

struct Edge {
    int to;
    long long cost;
    long long min_cost;
    Edge(int t, long long c, long long m) : to(t), cost(c), min_cost(m) {}
};

struct State {
    int node;
    long long total_cost;
    long long min_edge;
    State(int n, long long tc, long long me) : node(n), total_cost(tc), min_edge(me) {}
    bool operator>(const State& other) const {
        return total_cost > other.total_cost;
    }
};

long long solve(vector<vector<long long>> edges, vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<Edge>> graph(n);
    for (const auto& e : edges) {
        int u = e[0], v = e[1];
        long long cost = e[2];
        if (u == v) continue;
        graph[u].emplace_back(v, cost, cost);
    }

    priority_queue<State, vector<State>, greater<State>> pq;
    pq.emplace(0, 0, LLONG_MAX);
    long long max_score = -1;

    while (!pq.empty()) {
        State current = pq.top();
        pq.pop();
        int u = current.node;
        long long total_cost = current.total_cost;
        long long min_edge = current.min_edge;

        if (u == n - 1) {
            if (total_cost <= k) {
                if (min_edge != LLONG_MAX) {
                    max_score = max(max_score, min_edge);
                }
            }
            continue;
        }

        for (const Edge& edge : graph[u]) {
            int v = edge.to;
            if (v != n - 1 && !online[v]) continue;
            long long new_total = total_cost + edge.cost;
            if (new_total > k) continue;
            long long new_min = min(min_edge, edge.cost);
            pq.emplace(v, new_total, new_min);
        }
    }

    return max_score;
}

