        long long min_edge = current.min_edge;

        if (u == n - 1) {
            if (total_cost <= k) {
                if (min_edge != LLONG_MAX) {
                    max_score = max(max_score, min_edge);
                }
            }
            continue;
        }

        for (const Edge& edge : graph[u]) {
            int v = edge.to;
            if (v != n - 1 && !online[v]) continue;
            long long new_total = total_cost + edge.cost;
            if (new_total > k) continue;
            long long new_min = min(min_edge, edge.cost);
            pq.emplace(v, new_total, new_min);
        }
    }

    return max_score;
}
